const AWS = require('aws-sdk');
const bcrypt = require('bcryptjs');

// Configure AWS region (Lambda automatically sets process.env.AWS_REGION)
AWS.config.update({ region: process.env.AWS_REGION });

const dynamoDb = new AWS.DynamoDB.DocumentClient();

// DynamoDB table name must be set as an environment variable in Lambda
const TABLE_NAME = process.env.TABLE_NAME;

exports.handler = async (event) => {
    // Ensure TABLE_NAME is configured
    if (!TABLE_NAME) {
        console.error('Configuration Error: TABLE_NAME environment variable is not set.');
        return {
            statusCode: 500,
            body: JSON.stringify({ message: 'Internal server configuration error.' }),
        };
    }

    let body;
    try {
        // API Gateway sends the request body as a string
        body = JSON.parse(event.body);
    } catch (error) {
        console.error('Invalid JSON body received:', error);
        return {
            statusCode: 400,
            body: JSON.stringify({ message: 'Invalid request body. Expected JSON.' }),
        };
    }

    const { email, password } = body;

    // Input validation
    if (!email || !password) {
        return {
            statusCode: 400,
            body: JSON.stringify({ message: 'Email and password are required.' }),
        };
    }

    // Basic email format validation
    if (!/\S+@\S+\.\S+/.test(email)) {
        return {
            statusCode: 400,
            body: JSON.stringify({ message: 'Invalid email format.' }),
        };
    }

    // Basic password length validation
    if (password.length < 8) {
        return {
            statusCode: 400,
            body: JSON.stringify({ message: 'Password must be at least 8 characters long.' }),
        };
    }

    try {
        // Check if a user with this email already exists
        const existingUser = await dynamoDb.get({
            TableName: TABLE_NAME,
            Key: { email: email },
        }).promise();

        if (existingUser.Item) {
            return {
                statusCode: 409, // Conflict
                body: JSON.stringify({ message: 'User with this email already exists.' }),
            };
        }

        // Hash the password before storing it
        const saltRounds = 10; // Recommended salt rounds for bcrypt
        const hashedPassword = await bcrypt.hash(password, saltRounds);

        const params = {
            TableName: TABLE_NAME,
            Item: {
                email: email,
                hashedPassword: hashedPassword,
                createdAt: new Date().toISOString(), // Timestamp for when the user was created
            },
        };

        await dynamoDb.put(params).promise();

        return {
            statusCode: 200,
            body: JSON.stringify({ message: 'User registered successfully!' }),
        };
    } catch (error) {
        console.error('Error during user registration:', error);
        return {
            statusCode: 500,
            body: JSON.stringify({ message: 'Failed to register user.', error: error.message }),
        };
    }
};